import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Finding Trustworthy Mods","description":"A guide on how to find Fabric mods using trustworthy sources.","frontmatter":{"title":"Finding Trustworthy Mods","description":"A guide on how to find Fabric mods using trustworthy sources.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"1.21.10/players/finding-mods.md","filePath":"versions/1.21.10/players/finding-mods.md","lastUpdated":1766682904000}`);var a={name:`1.21.10/players/finding-mods.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Finding Trustworthy Mods <a class="header-anchor" href="#h1" aria-label="Permalink to “Finding Trustworthy Mods”">​</a></h1><p>Firstly, trust is subjective, and you should always use your own judgement when downloading mods. However, there are some things you can do to help you find trustworthy mods.</p><h2 id="trustworthy-source" tabindex="-1">1. Use a Source That Is Known to Be Trustworthy <a class="header-anchor" href="#trustworthy-source" aria-label="Permalink to “1. Use a Source That Is Known to Be Trustworthy”">​</a></h2><p>The majority of authors publish their mods to <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> and <a href="https://www.curseforge.com/minecraft/search?class=mc-mods&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a>.</p><p>These websites check that the mods are what they say they are, and that they do not contain malicious code. You can also report malicious mods on those websites, and they will take action relatively quickly.</p><h2 id="with-others" tabindex="-1">2. Check With Others! <a class="header-anchor" href="#with-others" aria-label="Permalink to “2. Check With Others!”">​</a></h2><p>If you are downloading a mod from a source that is not known to be trustworthy, you should check with others to see if they have downloaded the mod before from the location you&#39;re downloading from, and if they have had any issues with it.</p><p>If in doubt, you are welcome to ask in the <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> in the <code>#player-support</code> channel.</p><h2 id="avoid-malware" tabindex="-1">3. Avoid Common Malware Sites! <a class="header-anchor" href="#avoid-malware" aria-label="Permalink to “3. Avoid Common Malware Sites!”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Malware sites may not be obvious to everyone. If you are unsure, you should ask for opinions from others or avoid the site altogether and rely only on trusted sources, such as Modrinth and CurseForge.</p></div><p>There are a lot of websites that claim to have mods for Minecraft, but are actually just malware sites. You should avoid these sites at all costs.</p><p>You can use antivirus software and websites like <a href="https://www.microsoft.com/en-us/windows/comprehensive-security" target="_blank" rel="noreferrer">Windows Defender</a> or <a href="https://www.virustotal.com/" target="_blank" rel="noreferrer">VirusTotal</a> to check the downloaded mods. However, do not rely entirely on those methods, because they can be sometimes incorrect.</p><p>Again, if in doubt, you are welcome to ask for opinions in the <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> in the <code>#player-support</code> channel.</p>`,13)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};